               try{                          /* Start of a Try block for Executing SQL Statements */    String query = "INSERT INTO Employee (id , name ) VALUES ('123', 'Test User')";     conn.createStatement().executeUpdate(query);      }catch (SQLException e) { println("Error occurred during execution: ",e );}  // Catch any exception thrown if it arises here, then end the program gracefully by calling system exit method '.exit'
